/**
 * 提取 Lucide 官方图标 SVG path 数据
 * 将 Lucide 的数组表示法转为 SVG 元素字符串
 */

const icons = {
  Dumbbell: "dumbbell",
  BookOpen: "book-open",
  Sparkles: "sparkles",
  Briefcase: "briefcase",
  Brain: "brain",
  Landmark: "landmark",
  Globe: "globe",
  Home: "home",
  Target: "target",
  Palette: "palette",
  Music: "music",
  Pen: "pen",
  Flower2: "lotus",
  HeartPulse: "heart-pulse",
  Laptop: "laptop",
  Clipboard: "clipboard",
  Film: "film",
  MessageCircle: "message-circle",
  Compass: "compass",
  Microscope: "microscope",
  BarChart3: "bar-chart",
  Lightbulb: "lightbulb",
  Star: "star",
  Package: "package",
  Bot: "bot",
  Award: "award",
  ClipboardList: "clipboard-list",
  Check: "check",
  X: "x",
};

/** 将 Lucide 元素数组转为 SVG 元素字符串 */
function toSvgElements(elements) {
  return elements.map(([tag, attrs]) => {
    const attrStr = Object.entries(attrs)
      .map(([k, v]) => `${k}="${v}"`)
      .join(" ");
    return `<${tag} ${attrStr} />`;
  }).join("");
}

async function main() {
  try {
    const lucide = await import("lucide");

    for (const [lucideName, iconName] of Object.entries(icons)) {
      const data = lucide[lucideName];
      if (!data) {
        console.log(`// ${lucideName} -> ${iconName}: MISSING`);
        continue;
      }
      const svg = toSvgElements(data);
      console.log(`// ${lucideName} -> ${iconName}`);
      console.log(`"${iconName}": { paths: \`${svg}\` },`);
    }

    // 也输出 Star 的 SVG 字符串（mood 图标也用）
    const starData = lucide["Star"];
    if (starData) {
      console.log("\n// Star SVG for mood icons:");
      console.log(toSvgElements(starData));
    }
  } catch (e) {
    console.error("Error:", e.message);
    process.exit(1);
  }
}

main();

