import { Image } from "@tarojs/components";
import { memo, useMemo } from "react";
import { ICON_PATHS, PLACEHOLDER } from "./iconPaths";

export type IconName =
  | "dumbbell" | "book-open" | "sparkles" | "briefcase"
  | "brain" | "landmark" | "globe" | "home"
  | "target" | "palette" | "music" | "pen"
  | "lotus" | "runner" | "heart-pulse" | "laptop"
  | "clipboard" | "film" | "message-circle" | "compass"
  | "microscope" | "bar-chart" | "lightbulb" | "star"
  | "package" | "bot" | "award" | "clipboard-list"
  | "check" | "x"
  | "mood-1" | "mood-2" | "mood-3" | "mood-4" | "mood-5";

export type IconColor = "primary" | "secondary" | "accent" | "muted" | "faded";

export interface IconProps {
  name: IconName;
  size?: number;
  color?: IconColor;
}

const COLOR_MAP: Record<IconColor, string> = {
  primary: "#e8e0d6",
  secondary: "#a89f92",
  accent: "#c4843e",
  muted: "#7a7268",
  faded: "#4a4540",
};

/** 纯 JS base64 编码（ASCII 安全，不依赖 btoa / TextEncoder） */
function toBase64(str: string): string {
  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  const bytes: number[] = [];
  for (let i = 0; i < str.length; i++) {
    bytes.push(str.charCodeAt(i));
  }

  let result = "";
  for (let i = 0; i < bytes.length; i += 3) {
    const a = bytes[i];
    const b = i + 1 < bytes.length ? bytes[i + 1] : null;
    const c = i + 2 < bytes.length ? bytes[i + 2] : null;

    result += chars[a >> 2];
    result += chars[((a & 3) << 4) | (b !== null ? b >> 4 : 0)];

    if (b === null) {
      result += "==";
    } else {
      result += chars[((b & 15) << 2) | (c !== null ? c >> 6 : 0)];
      if (c === null) {
        result += "=";
      } else {
        result += chars[c & 63];
      }
    }
  }
  return result;
}

/** 根据图标定义和颜色生成 base64 data URI */
function buildSvgSrc(name: IconName, colorHex: string): string {
  const icon = ICON_PATHS[name];
  if (!icon) return "";

  // 替换路径中的占位符和 currentColor（Palette 等图标用）
  const paths = icon.paths
    .replace(new RegExp(PLACEHOLDER, "g"), colorHex)
    .replace(/currentColor/g, colorHex);

  // 确定 fill 值：有定义则用（含 {{COLOR}} 替换），否则默认 "none"
  const fillValue = icon.fill
    ? icon.fill.replace(new RegExp(PLACEHOLDER, "g"), colorHex)
    : "none";

  const parts: string[] = [
    '<svg xmlns="http://www.w3.org/2000/svg"',
    ' width="24" height="24" viewBox="0 0 24 24"',
    ' fill="' + fillValue + '"',
    ' stroke="' + colorHex + '"',
    ' stroke-width="2"',
    ' stroke-linecap="round"',
    ' stroke-linejoin="round"',
  ];

  if (icon.fillOpacity) {
    parts.push(' fill-opacity="' + icon.fillOpacity + '"');
  }

  parts.push(">", paths, "</svg>");

  return "data:image/svg+xml;base64," + toBase64(parts.join(""));
}

/** 兜底：用 star 作为 fallback */
const FALLBACK_NAME: IconName = "star";

function Icon({ name, size = 48, color = "primary" }: IconProps) {
  const colorHex = COLOR_MAP[color];

  const svgSrc = useMemo(() => {
    return buildSvgSrc(name, colorHex) || buildSvgSrc(FALLBACK_NAME, colorHex);
  }, [name, colorHex]);

  return (
    <Image
      src={svgSrc}
      mode="aspectFit"
      style={{ width: size + "rpx", height: size + "rpx" }}
    />
  );
}

export default memo(Icon);
